import React, { useEffect, useState } from 'react';
import { seasonService, pondService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/manager/manager-common.css';
import '../../styles/manager/manager-seasons.css';
import { pushToast } from "../../utils/toastBridge";
const emptyCreateForm = {
  pondId: '',
  seasonName: '',
  startDate: '',
  shrimpType: '',
  density: ''
};
const emptyHarvestForm = {
  actualHarvestDate: '',
  note: ''
};
const formatVietnameseDate = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const formatRoundedNumber = value => {
  if (value === null || value === undefined || value === '') return '-';
  const numberValue = Number(value);
  if (Number.isNaN(numberValue)) return value;
  return String(Math.round(numberValue));
};
const ManagerSeasons = () => {
  const [seasons, setSeasons] = useState([]);
  const [ponds, setPonds] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const error = null;
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showHarvestModal, setShowHarvestModal] = useState(false);
  const [selectedSeason, setSelectedSeason] = useState(null);
  const [createForm, setCreateForm] = useState(emptyCreateForm);
  const [harvestForm, setHarvestForm] = useState(emptyHarvestForm);
  useEffect(() => {
    fetchData();
  }, []);
  const fetchData = async () => {
    try {
      setLoading(true);
      const [seasonsRes, pondsRes] = await Promise.all([seasonService.getAllSeasons(), pondService.getAllPonds()]);
      setSeasons(seasonsRes?.data?.data || []);
      setPonds(pondsRes?.data?.data || []);
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c dá»¯ liá»‡u mÃ¹a vá»¥',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  };
  const getPondName = pondId => {
    if (!pondId) return '-';
    const found = ponds.find(p => p.pond_id === pondId);
    return found ? found.pond_name || found.pond_code : '-';
  };
  const openCreateModal = () => {
    setCreateForm(emptyCreateForm);
    setShowCreateModal(true);
  };
  const openHarvestModal = season => {
    setSelectedSeason(season);
    setHarvestForm(emptyHarvestForm);
    setShowHarvestModal(true);
  };
  const handleCreateChange = (field, value) => {
    setCreateForm(prev => ({
      ...prev,
      [field]: value
    }));
  };
  const handleHarvestChange = (field, value) => {
    setHarvestForm(prev => ({
      ...prev,
      [field]: value
    }));
  };
  const handleCreateSubmit = async event => {
    event.preventDefault();
    try {
      setSaving(true);
      await seasonService.createSeason({
        pondId: Number(createForm.pondId),
        seasonName: createForm.seasonName.trim(),
        startDate: createForm.startDate,
        shrimpType: createForm.shrimpType.trim(),
        density: Number(createForm.density)
      });
      setShowCreateModal(false);
      setCreateForm(emptyCreateForm);
      await fetchData();
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'KhÃ´ng táº¡o Ä‘Æ°á»£c mÃ¹a vá»¥',
        type: "error"
      });
    } finally {
      setSaving(false);
    }
  };
  const handleHarvestSubmit = async event => {
    event.preventDefault();
    try {
      setSaving(true);
      await seasonService.harvestSeason(selectedSeason.season_id, {
        actualHarvestDate: harvestForm.actualHarvestDate,
        note: harvestForm.note.trim() || null
      });
      setShowHarvestModal(false);
      setSelectedSeason(null);
      setHarvestForm(emptyHarvestForm);
      await fetchData();
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'KhÃ´ng káº¿t thÃºc mÃ¹a vá»¥',
        type: "error"
      });
    } finally {
      setSaving(false);
    }
  };
  return <div className="dashboard-container manager-page">
      <div className="card">
        <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '1rem'
      }}>
          <h3>Danh sÃ¡ch mÃ¹a vá»¥</h3>
          <button className="btn btn-primary" onClick={openCreateModal}>
            + Táº¡o mÃ¹a vá»¥ má»›i
          </button>
        </div>
        <div className="table-responsive">
          <table className="table">
            <thead>
              <tr>
                <th>Ao</th>
                <th>TÃªn mÃ¹a vá»¥</th>
                <th>Loáº¡i tÃ´m</th>
                <th>NgÃ y tháº£</th>
                <th>Máº­t Ä‘á»™</th>
                <th>Dá»± kiáº¿n Thu hoáº¡ch</th>
                <th>Tráº¡ng thÃ¡i</th>
                <th>HÃ nh Ä‘á»™ng</th>
              </tr>
            </thead>
            <tbody>
              {loading ? <tr><td colSpan="8">Äang táº£i...</td></tr> : seasons.length === 0 ? <tr><td colSpan="8">ChÆ°a cÃ³ mÃ¹a vá»¥ nÃ o</td></tr> : seasons.map(season => <tr key={season.season_id}>
                    <td>{getPondName(season.pond_id)}</td>
                    <td>{season.season_name}</td>
                    <td>{season.shrimp_type}</td>
                    <td>{formatVietnameseDate(season.start_date)}</td>
                    <td>{formatRoundedNumber(season.density)}</td>
                    <td>{formatVietnameseDate(season.expected_harvest)}</td>
                    <td>
                      <span className={`manager-seasons__status ${season.status === 'RUNNING' ? 'manager-seasons__status--running' : 'manager-seasons__status--finished'}`}>
                        {season.status === 'RUNNING' ? 'ðŸ”„ RUNNING' : 'âœ“ FINISHED'}
                      </span>
                    </td>
                    <td className="manager-seasons__action-cell">
                      {season.status === 'RUNNING' && <button className="btn btn-success" onClick={() => openHarvestModal(season)}>Thu hoáº¡ch</button>}
                    </td>
                  </tr>)}
            </tbody>
          </table>
        </div>
      </div>

      {/* Create Season Modal */}
      {showCreateModal && <div className="modal" onClick={() => setShowCreateModal(false)}>
          <div className="modal-content manager-seasons__modal" onClick={e => e.stopPropagation()}>
            <h3 className="manager-seasons__modal-title">Táº¡o mÃ¹a vá»¥ má»›i</h3>
            <form onSubmit={handleCreateSubmit}>
              <div className="form-group">
                <label>Ao nuÃ´i</label>
                <select className="input" value={createForm.pondId} onChange={e => handleCreateChange('pondId', e.target.value)} required>
                  <option value="">-- Chá»n ao --</option>
                  {ponds.map(pond => <option key={pond.pond_id} value={pond.pond_id}>
                      {pond.pond_code} - {pond.pond_name}
                    </option>)}
                </select>
              </div>

              <div className="form-group">
                <label>TÃªn mÃ¹a vá»¥</label>
                <input className="input" value={createForm.seasonName} onChange={e => handleCreateChange('seasonName', e.target.value)} placeholder="VD: MÃ¹a 1/2024" required />
              </div>

              <div className="form-group">
                <label>NgÃ y tháº£ (Start Date)</label>
                <input className="input" type="date" value={createForm.startDate} onChange={e => handleCreateChange('startDate', e.target.value)} required />
              </div>

              <div className="form-group">
                <label>Loáº¡i tÃ´m</label>
                <input className="input" value={createForm.shrimpType} onChange={e => handleCreateChange('shrimpType', e.target.value)} placeholder="VD: TÃ´m sÃº, TÃ´m tháº» chÃ¢n tráº¯ng" required />
              </div>

              <div className="form-group">
                <label>Máº­t Ä‘á»™</label>
                <input className="input" type="number" step="0.01" value={createForm.density} onChange={e => handleCreateChange('density', e.target.value)} placeholder="Máº­t Ä‘á»™ nuÃ´i (con/mÂ²)" required />
              </div>

              <div className="manager-seasons__actions">
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  ðŸ’¾ {saving ? 'Äang táº¡o' : 'Táº¡o mÃ¹a vá»¥'}
                </button>
                <button type="button" className="btn btn-secondary" onClick={() => setShowCreateModal(false)}>
                  âŒ Há»§y
                </button>
              </div>
            </form>
          </div>
        </div>}

      {/* Harvest Season Modal */}
      {showHarvestModal && selectedSeason && <div className="modal" onClick={() => setShowHarvestModal(false)}>
          <div className="modal-content manager-seasons__modal manager-seasons__modal--harvest" onClick={e => e.stopPropagation()}>
            <h3 className="manager-seasons__modal-title">Thu hoáº¡ch mÃ¹a vá»¥</h3>
            <form onSubmit={handleHarvestSubmit}>
              <div className="manager-seasons__harvest-box">
                <p><strong>Ao:</strong> {getPondName(selectedSeason.pond_id)}</p>
                <p><strong>MÃ¹a vá»¥:</strong> {selectedSeason.season_name}</p>
                <p><strong>Loáº¡i tÃ´m:</strong> {selectedSeason.shrimp_type}</p>
                <p><strong>NgÃ y tháº£:</strong> {formatVietnameseDate(selectedSeason.start_date)}</p>
              </div>

              <div className="form-group">
                <label>NgÃ y Thu hoáº¡ch (Actual Harvest)</label>
                <input className="input" type="date" value={harvestForm.actualHarvestDate} onChange={e => handleHarvestChange('actualHarvestDate', e.target.value)} required />
              </div>

              <div className="form-group">
                <label>Ghi chÃº</label>
                <textarea className="input" value={harvestForm.note} onChange={e => handleHarvestChange('note', e.target.value)} placeholder="Ghi chÃº vá» mÃ¹a vá»¥ (tÃ¹y chá»n)" rows="3"></textarea>
              </div>

              <div className="manager-seasons__actions">
                <button type="submit" className="btn btn-success" disabled={saving}>
                  ðŸŽ¯ {saving ? 'Äang lÆ°u' : 'Thu hoáº¡ch'}
                </button>
                <button type="button" className="btn btn-secondary" onClick={() => setShowHarvestModal(false)}>
                  âŒ Há»§y
                </button>
              </div>
            </form>
          </div>
        </div>}
    </div>;
};
export default ManagerSeasons;
